    color: 'rgba(255,255,255,0.35)',
    fontSize: 14,
    fontWeight: 400
  },
  noContent: {
    textAlign: 'center',
    padding: '60px 0'
  },
  secCard: {
    background: '#1a1a2e',
    borderRadius: 12,
    marginBottom: 10,
    border: '1px solid rgba(255,255,255,0.07)',
    overflow: 'hidden'
  },
  secHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '14px 18px',
    cursor: 'pointer',
    userSelect: 'none'
  },
  secLeft: {
    display: 'flex',
    alignItems: 'center',
    gap: 10
  },
  secToggle: {
    color: '#c8973a',
    fontWeight: 700,
    fontSize: 16,
    width: 20
  },
  secNum: {
    color: 'rgba(255,255,255,0.3)',
    fontSize: 12,
    fontWeight: 600
  },
  secTitle: {
    color: '#fff',
    fontWeight: 700,
    fontSize: 15
  },
  secCount: {
    color: 'rgba(255,255,255,0.35)',
    fontSize: 13
  },
  lecList: {
    borderTop: '1px solid rgba(255,255,255,0.06)'
  },
  lecRow: (active, locked) => ({
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
